import{_ as a,o as t,c as n,j as r,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"无门无派","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/太吾绘卷/无门无派.md","filePath":"4.资源分区/6.技艺及称号/武技类/太吾绘卷/无门无派.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/太吾绘卷/无门无派.md"};function p(b,e,l,_,i,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"无门无派",tabindex:"-1"},[s("无门无派 "),r("a",{class:"header-anchor",href:"#无门无派","aria-label":'Permalink to "无门无派"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风021")])])],-1),o('<h1 id="无门无派-1" tabindex="-1">无门无派 <a class="header-anchor" href="#无门无派-1" aria-label="Permalink to &quot;无门无派&quot;">​</a></h1><p>无门无派</p><p>内功-【沛然诀】<br> D+500<br> 沛然诀于内力收发引化之法中另辟蹊径，纳气不吐反复调练，所谓：“博观而约取，厚积而薄发”，功力愈用愈多，越是消耗，越显精强。<br> 你开启了内力能量池，但并不获得【基础内功】中内力的基础用法。<br> 现在你即便不处于适合休息的环境，只要周围没有敌方单位存在，你便可以进行长休息/短休息。</p><p>身法-【小纵跃功】<br> D+500<br> 小纵跃功乃是以连续的纵跃快速行动的粗浅轻功，虽然修习法门十分简单，但修习过程极长，非数十年寒暑不能练就，故而功法虽简，修习者却寥寥无几。<br> 你的移动速度提升15米。<br> 你现在可以免疫自然坠落伤害。</p><p>拳法-【太祖长拳】<br> D+500<br> 属性：无属性<br> 使用专业：拳<br> 消耗动作：标准动作<br> 属性：混元<br> 太祖长拳共有三十二式，朴实无华，简单纯粹，虽然招式粗浅，却已含拳术至理，故而人称“百拳之母”。<br> 对敌人进行一次肉搏攻击检定，造成钝击伤害。这次攻击具有5dp的技艺加值以及1点来自于技艺的附加成功。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=a(d,[["render",p]]);export{f as __pageData,m as default};
